  ('judicial-57f41407-moex-00843', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '當事人承認他造主張之事實，下列何者非屬訴訟法上之自認？', '["於準備書狀內", "在受命法官前", "在受託法官前", "在存證信函內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00844', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '原告甲與被告乙間之訴訟，甲於言詞辯論中為訴之變更，乙異議。法院以變更合法而裁定准許甲之變 更。下列敘述何者正確？', '["乙對該裁定得上訴", "乙對該裁定不得聲明不服", "乙對該裁定得抗告", "乙對該裁定得聲明異議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00845', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者，被告不負舉證責任？', '["原告基於消費借貸契約，請求被告返還借款，被告抗辯該消費借貸債權之成立，係基於通謀虛偽意 思表示之事實", "原告請求確認與被告間之委任關係不存在，被告抗辯該委任關係存在之事實", "原告主張債務人即被告之行為有害及債權，基於民法第244條規定，提起撤銷債權之訴，關於該形 成權已逾除斥期間之事實", "原告因被告駕駛汽車發生車禍而受傷，依侵權行為法律關係，起訴請求損害賠償，關於因果關係之 存否"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00846', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於言詞辯論，下列敘述何者正確？', '["攻擊防禦方法，當事人得於言詞辯論終結前之任何時期提出", "因採公開審理主義，所有法庭活動皆應公開", "因採不告不理原則，故原告之聲明若不完足者，法院不須闡明", "言詞辯論，以當事人聲明應受裁判之事項為始"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00847', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於法院調解，下列敘述何者正確？', '["本於票據有所請求而涉訟者，其訴訟標的價額逾新臺幣（下同）50萬元者，於起訴前應經法院調解", "建築物區分所有人相互間因建築物或其共同部分之管理發生爭執者，於起訴前應經法院調解", "配偶或直系血親相互間因財產權發生爭執，其訴訟標的價額逾50萬元者，於起訴前毋庸經法院調解", "因道路交通事故發生爭執，其訴訟標的價額逾50萬元，於起訴前毋庸經法院調解"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00848', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '適用簡易訴訟程序事件之第一審程序，對下列何者之通知得不以通知書為之？', '["原告", "被告", "原告之訴訟代理人", "鑑定人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00849', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '當事人於小額事件第一審判決送達後，提起第二審上訴，未於上訴狀載明上訴理由者，應於下列何期 間內提出上訴理由？', '["提起上訴後7日內", "上訴狀繕本送達被上訴人後7日內", "提起上訴後10日內", "提起上訴後20日內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00850', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲起訴請求乙返還借款新臺幣（下同）500萬元，經第一審判決乙應給付甲200萬元，駁回甲其餘請 求。甲、乙就其敗訴部分均聲明不服，提起上訴。嗣於第二審言詞辯論終結前，甲具狀表示兩造於訴 訟外已達成和解，因此撤回其上訴。下列敘述何者正確？', '["甲撤回上訴，縱然乙未撤回上訴，仍得請求退還甲於第二審所繳裁判費三分之二", "甲撤回其撤回上訴之意思表示時，第二審法院仍應繼續審理本件訴訟", "本件訴訟因甲具狀表示兩造達成和解，則和解成立，與確定判決有同一效力，本件全部第二審程序 即為終結", "甲因撤回上訴，即喪失其上訴權，就第一審對其不利部分之判決，即無從以任何方式再聲明不服"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00851', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於抗告程序，下列敘述何者正確？', '["均不得提出新攻擊防禦方法", "抗告法院為裁定前應行言詞辯論程序", "抗告法院認抗告為有理由者，應將原裁定廢棄，發回原法院更為裁定", "對於准為假扣押之裁定提起抗告，抗告法院為裁定前，應使債權人及債務人有陳述意見之機會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00852', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '再審原告依民事訴訟法第496條第1項第13款規定，以發現未經斟酌之證物為由，就第三審確定判 決向第三審法院提起再審之訴，第三審法院應如何處理？', '["應為實體裁判", "應以不合法裁定駁回", "應裁定移送於原第二審法院", "視再審被告是否抗辯無管轄權再為准駁之裁判"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
